Printed Tunic',0,1,'2026-06-04 06:08:29','2026-06-04 06:08:29'),(2138,2137,NULL,'https://res.cloudinary.com/dja44yh3w/image/upload/v1780578512/uniform/products/kaggle-18957-7a167685.jpg','uniform/products/kaggle-18957-7a167685','United Colors of Benetton Women Solid Grey Knitted Jacket',0,1,'2026-06-04 06:08:32','2026-06-04 06:08:32');
INSERT INTO `brand_translations` (`id`, `brand_id`, `locale`, `description`, `is_auto_translated`, `translated_at`, `created_at`, `updated_at`) VALUES (7,13,'en','Smart-casual menswear and womenswear bringing relaxed sophistication to the everyday wardrobe.',0,'2026-06-12 17:09:46','2026-06-12 17:05:15','2026-06-12 17:09:46'),(8,3,'en','A design-led label crafting minimalist everyday essentials built to last.',0,'2026-06-12 17:09:46','2026-06-12 17:05:15','2026-06-12 17:09:46'),(9,8,'en','Graphic-driven streetwear that turns bold prints and high contrast into wearable statements.',0,'2026-06-12 17:09:46','2026-06-12 17:05:15','2026-06-12 17:09:46'),(10,17,'en','Iconic denim heritage: timeless jeans and casual staples worn across generations.',0,'2026-06-12 17:09:46','2026-06-12 17:05:15','2026-06-12 17:09:46'),(11,14,'en','Contemporary European fashion with effortless, on-trend pieces for the modern wardrobe.',0,'2026-06-12 17:09:46','2026-06-12 17:05:15','2026-06-12 17:09:46'),(12,4,'en','Monochrome-focused basics and clean silhouettes for a pared-back, modern look.',0,'2026-06-12 17:09:46','2026-06-12 17:05:15','2026-06-12 17:09:46'),(13,2,'en','Outdoor-inspired apparel made for layering, movement, and cold-weather adventures.',0,'2026-06-12 17:09:46','2026-06-12 17:05:15','2026-06-12 17:09:46'),(14,16,'en','Affordable, polished menswear: shirts, trousers, and tailoring for work and beyond.',0,'2026-06-12 17:09:46','2026-06-12 17:05:16','2026-06-12 17:09:46'),(15,5,'en','Laid-back, water-inspired casualwear for easy days and weekend escapes.',0,'2026-06-12 17:09:46','2026-06-12 17:05:16','2026-06-12 17:09:46'),(16,12,'en','Rugged casual and denim staples built for everyday adventure and the open road.',0,'2026-06-12 17:09:46','2026-06-12 17:05:16','2026-06-12 17:09:46'),(17,6,'en','Urban streetwear with bold attitude, oversized fits, and statement graphics.',0,'2026-06-12 17:09:46','2026-06-12 17:05:16','2026-06-12 17:09:46'),(18,7,'en','A youthful streetwear label mixing retro energy with modern everyday silhouettes.',0,'2026-06-12 17:09:46','2026-06-12 17:05:16','2026-06-12 17:09:46'),(19,1,'en','Vesta is our house label: statement streetwear with virtual try-on built in, designed to be worn your way.',0,'2026-06-12 17:09:46','2026-06-12 17:05:16','2026-06-12 17:09:46'),(20,15,'en','Western-rooted denim and rugged workwear built tough for real life.',0,'2026-06-12 17:09:46','2026-06-12 17:05:16','2026-06-12 17:09:46'),(49,21,'en','Performance-first activewear engineered for training, movement, and the everyday athlete.',0,'2026-06-12 17:09:46','2026-06-12 17:09:46','2026-06-12 17:09:46'),(50,20,'en','Sport and lifestyle gear built for performance, comfort, and everyday motion.',0,'2026-06-12 17:09:46','2026-06-12 17:09:46','2026-06-12 17:09:46'),(51,19,'en','Athletic-rooted sportswear blending performance with street-ready style.',0,'2026-06-12 17:09:46','2026-06-12 17:09:46','2026-06-12 17:09:46'),(52,18,'en','Vibrant, colourful knitwear and casualwear celebrating diversity and everyday style.',0,'2026-06-12 17:09:46','2026-06-12 17:09:46','2026-06-12 17:09:46'),(53,1,'vi','Vesta là thương hiệu riêng của chúng tôi: những thiết kế thời trang đường phố đầy cá tính, tích hợp tính năng thử đồ ảo, được thiết kế để bạn có thể mặc theo phong cách riêng của mình.',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(54,2,'vi','Bộ sưu tập thời trang lấy cảm hứng từ thiên nhiên, được thiết kế để mặc lớp, thoải mái vận động và khám phá trong thời tiết lạnh.',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(55,3,'vi','Một thương hiệu lấy thiết kế làm trọng tâm, chuyên tạo ra những món đồ thiết yếu hàng ngày theo phong cách tối giản và bền bỉ.',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(56,4,'vi','Những món đồ cơ bản với tông màu đơn sắc và đường nét gọn gàng, mang đến phong cách tối giản và hiện đại.',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(57,5,'vi','Bộ sưu tập thời trang dạo phố thoải mái, lấy cảm hứng từ nước, dành cho những ngày thư giãn và những chuyến đi cuối tuần.',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(58,6,'vi','Thời trang dạo phố mang phong cách táo bạo, kiểu dáng rộng rãi và họa tiết nổi bật.',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(59,7,'vi','Một thương hiệu thời trang đường phố trẻ trung, kết hợp tinh thần retro với những kiểu dáng hiện đại dành cho cuộc sống hàng ngày.',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(60,8,'vi','Thời trang dạo phố lấy họa tiết làm chủ đạo, biến những họa tiết táo bạo và sự tương phản mạnh mẽ thành những tuyên ngôn thời trang đầy cá tính.',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(61,12,'vi','Những món đồ cơ bản phong cách casual và denim bền bỉ, được thiết kế dành cho những cuộc phiêu lưu hàng ngày và những chuyến đi trên đường trường.',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(62,13,'vi','Thời trang nam và nữ theo phong cách smart-casual, mang đến nét thanh lịch thoải mái cho tủ đồ hàng ngày.',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(63,14,'vi','Thời trang châu Âu đương đại với những thiết kế đơn giản, hợp xu hướng, phù hợp với tủ đồ của người phụ nữ hiện đại.',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(64,15,'vi','Quần jean mang đậm phong cách phương Tây và trang phục lao động bền bỉ, được thiết kế chắc chắn để phù hợp với cuộc sống thực tế.',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(65,16,'vi','Quần áo nam sang trọng với giá cả phải chăng: áo sơ mi, quần tây và trang phục may đo dành cho công sở và các dịp khác.',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(66,17,'vi','Di sản denim mang tính biểu tượng: những chiếc quần jean vượt thời gian và những món đồ cơ bản phong cách casual được yêu thích qua nhiều thế hệ.',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(67,18,'vi','Những bộ trang phục dệt kim và trang phục thường ngày tươi tắn, rực rỡ, tôn vinh sự đa dạng và phong cách thường ngày.',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(68,19,'vi','Thời trang thể thao lấy cảm hứng từ thể thao, kết hợp giữa tính năng vận động và phong cách đường phố.',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(69,20,'vi','Đồ dùng thể thao và phong cách sống được thiết kế để mang lại hiệu suất cao, sự thoải mái và phù hợp với mọi hoạt động hàng ngày.',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(70,21,'vi','Bộ sưu tập trang phục thể thao ưu tiên hiệu suất, được thiết kế dành riêng cho tập luyện, vận động và những người đam mê thể thao trong cuộc sống hàng ngày.',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(71,1,'ja','Vestaは当社のオリジナルブランドです。バーチャル試着機能を搭載した、自分らしく着こなせる個性的なストリートウェアを展開しています。',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(72,2,'ja','アウトドアからインスピレーションを得た、重ね着や動きやすさ、そして寒い季節の冒険に最適なアパレル。',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(73,3,'ja','デザインを重視したブランドが、長く愛用できるミニマルな日常使いの必需品を生み出しています。',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(74,4,'ja','モノトーンを基調としたベーシックなアイテムとすっきりとしたシルエットで、シンプルでモダンなスタイルを演出します。',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(75,5,'ja','ゆったりとした、水をモチーフにしたカジュアルウェア。のんびりとした日常や週末の小旅行にぴったりです。',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(76,6,'ja','大胆なスタイル、オーバーサイズフィット、そしてインパクトのあるグラフィックが特徴のアーバン・ストリートウェア。',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(77,7,'ja','レトロな雰囲気と現代的な日常着のシルエットを融合させた、若々しいストリートウェアブランド。',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(78,8,'ja','大胆なプリントと高いコントラストを、着こなせるファッションステートメントへと昇華させた、グラフィックを主軸としたストリートウェア。',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(79,12,'ja','毎日の冒険や旅路にぴったりの、タフでカジュアルなデニムの定番アイテム。',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(80,13,'ja','スマートカジュアルなメンズウェアとレディースウェアで、日常のワードローブに気取らない洗練さを添えます。',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(81,14,'ja','現代のワードローブにぴったりの、気取らずトレンド感のあるコンテンポラリー・ヨーロッパ・ファッション。',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(82,15,'ja','西洋発祥のデニムと、実生活で活躍できるよう頑丈に作られたタフなワークウェア。',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(83,16,'ja','手頃な価格で洗練されたメンズウェア：仕事やプライベートに最適なシャツ、パンツ、オーダーメイドスーツ。',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(84,17,'ja','デニムの象徴的な伝統：世代を超えて愛される、時代を超えたジーンズとカジュアルな定番アイテム。',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(85,18,'ja','多様性と日常のスタイルを称える、鮮やかでカラフルなニットウェアとカジュアルウェア。',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(86,19,'ja','アスレチックをルーツに持つスポーツウェア。機能性とストリートスタイルを融合させたデザイン。',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(87,20,'ja','パフォーマンス、快適性、そして日常の動きを追求して作られたスポーツ＆ライフスタイルギア。',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48'),(88,21,'ja','トレーニング、アクティブな動き、そして日常的にスポーツを楽しむ人々のために設計された、機能性を最優先にしたアクティブウェア。',1,'2026-06-12 17:09:48','2026-06-12 17:09:48','2026-06-12 17:09:48');
