INSERT INTO `product_translations` (`id`, `product_id`, `locale`, `name`, `description`, `is_auto_translated`, `translated_at`, `created_at`, `updated_at`) VALUES (1,1,'vi','Mũ đá cẩm thạch tuyệt đẹp','Sự phân biệt này được hình thành từ công sức này. Những điều cần loại bỏ đã được nhận ra rõ ràng. Việc thực hành này giống như nỗi đau. Đó là sự khoái lạc. Đối với chúng ta, những nỗi đau khắc nghiệt hơn so với những gì chúng ta mong muốn là điều tối thiểu.',1,'2026-06-12 17:00:04','2026-06-12 17:00:04','2026-06-12 17:00:04'),(2,2,'vi','Đèn len kiểu dáng thanh lịch','Ở đây, bởi vì có một số niềm vui. Những điều mà ai đó phải vất vả tìm kiếm. Chúng hòa quyện với tâm hồn và sự hài lòng của vạn vật. Chúng và những điều đó hòa quyện vào chính cuộc sống cùng với niềm vui. Những điều bị hủy hoại, những lời ngọt ngào, do đó, những niềm vui và sự hài lòng.',1,'2026-06-12 17:00:04','2026-06-12 17:00:04','2026-06-12 17:00:04'),(3,3,'vi','Găng tay đá hoa cương tiện dụng','Về cơ thể và nỗi đau. Bản thân nó cũng không kém phần quan trọng. Điều này giúp giải quyết các vấn đề hiện tại và mang lại cuộc sống.',1,'2026-06-12 17:00:04','2026-06-12 17:00:04','2026-06-12 17:00:04'),(4,4,'vi','Đĩa gỗ thông minh','Vì vậy, ai dám chê bai những lời khen ngợi trong thời đại ngày nay? Họ không biết rằng niềm vui trong cuộc sống chính là những khoái lạc đó. Và những nỗi đau, đặc biệt là những nỗi đau trong cuộc sống, còn khắc nghiệt hơn cả những vất vả. Ít đau khổ hơn. Có ai đó từ chối những nỗi đau lớn hơn, trừ khi họ chấp nhận.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(5,5,'vi','Túi len thiết kế theo nguyên tắc công thái học','Chúng tôi cáo buộc những bậc cao quý rằng các ngài không nhận ra điều đó. Bởi lẽ, những điều khắc nghiệt trong cuộc sống lại mang đến niềm vui. Chúng tôi không tìm thấy niềm vui nào khi những điều hiện tại trốn tránh những điều khắc nghiệt. Sự phân biệt đó chính là nhu cầu.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(6,6,'vi','Áo sơ mi nhôm bóng bẩy','Trong những thời điểm thuận lợi, hãy chọn những điều khác. Đối với một số người, mọi thứ đều bình đẳng, trừ khi có những rắc rối không bao giờ xảy ra. Niềm vui mang lại cho chúng ta sự thoải mái.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(7,7,'vi','Bàn phím da tuyệt vời','Những khoảnh khắc ấy thật đáng yêu. Sự trốn chạy khỏi những lời ngọt ngào mang lại niềm vui. Niềm vui ấy chính là lỗi lầm của chúng ta. Họ không biết rằng những khoảnh khắc ấy mang lại niềm vui. Niềm vui ấy mang lại nỗi đau tột cùng.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(8,8,'vi','Túi đồng nhỏ','Bởi vì cần phải loại bỏ những điều gây phiền toái. Hãy nhận ra những niềm vui trong cuộc sống. Việc loại bỏ những phiền toái sẽ mang lại những điều tốt đẹp.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(9,9,'vi','Máy tính sắt kỳ diệu','Chúng tôi không để bất kỳ trở ngại nào cản trở việc tìm kiếm những rắc rối của chúng tôi. Họ không biết rằng những khó khăn đó là điều cần thiết. Những khó khăn đó dẫn đến những rắc rối bị che khuất.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(10,10,'vi','Đèn bông vải bình thường','Những nghĩa vụ quan trọng nhất không phải là điều đó. Sự cản trở được loại trừ, nhưng vấn đề đã được giải quyết. Những điều khôn ngoan xuất hiện. Bởi vì nỗi đau và sự ghét bỏ, họ không biết niềm vui, và những điều đó cần phải bị bác bỏ. Từ đây, mọi điều đã được nói đều cần phải bị bác bỏ.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(11,11,'vi','Mũ nhựa nhỏ','Chúng ta có thể chịu đựng nỗi đau. Điều đó không mang lại niềm vui. Thời gian trôi qua thật khó chịu. Nỗi đau lớn lao ấy đã giải thoát chúng ta khỏi nỗi đau, trừ khi... Cuộc sống được giải thoát khỏi sự tham lam, để cuộc sống được cân bằng với những điều đó.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(12,12,'vi','Áo khoác gỗ phong cách mộc mạc','Hãy để những điều thuộc về cơ thể và cuộc sống hiện hữu. Hãy để những điều thuận lợi được thực hiện một cách trôi chảy. Tuy nhiên, điều đó cũng phải dựa trên lý lẽ. Bản thân những nỗ lực đó, có những điều mà người ta không biết. Niềm vui không phải là sự trốn chạy, mà là vì kiến trúc sư đã làm cho nó trở nên gồ ghề.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(13,13,'vi','Đĩa giấy chịu lực cao','Những điều cần bác bỏ trong những điều hiện tại của ông. Bởi vì khi chúng ta nghe những lời khen ngợi. Việc từ chối những điều đó là sự lựa chọn, chứ không phải sự chỉ trích những điều vốn dĩ không có gì. Những rắc rối trong việc thực hành các sự việc. Họ không biết lý do nào cả.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(14,14,'vi','Chiếc xe nhựa tuyệt vời','Các trường hợp miễn trừ trong các quy định đó. Những người được chọn khác. Bởi vì những niềm vui dễ dàng.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(15,15,'vi','Đồng hồ nhôm bền bỉ','Tôi sẽ giải thích điều đó, nhưng không thể giải thích hết được. Bởi lẽ, lỗi lầm cần phải gánh chịu những phiền toái ít hơn so với lẽ phải. Những điều đó không bao giờ có thể mang lại sự hài lòng cho cơ thể, và tôi cũng không thể giải thích hết được.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(16,16,'vi','Bàn phím len thiết kế thanh lịch','Chúng ta không biết điều đó. Vào thời điểm đó, những người đáng kính nhất đã nỗ lực hết mình để mang lại niềm vui. Sự nỗ lực đó đã xua tan mọi khó khăn. Đó là một thời kỳ vĩ đại, khi nỗi đau được giải tỏa.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(17,17,'vi','Mũ giấy thiết kế theo nguyên tắc công thái học','Hãy làm những điều khiến tâm hồn họ vui sướng. Hãy từ chối những điều khiến họ không hài lòng. Bởi vì điều đó đòi hỏi sự nỗ lực và cần được giải quyết một cách hợp lý.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(18,18,'vi','Bàn phím cao su tuyệt vời','Thường thì chúng ta ghét người kiến trúc sư của nỗi đau. Điều đó khiến nỗi ghét này càng thêm sâu đậm. Nỗi đau dễ dàng bị hủy hoại bởi sự vất vả. Ai là người che giấu những điều mình yêu mến? Những rắc rối tiếp nối nhau theo thời gian, giống như những điều tương tự.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(19,19,'vi','Mũ sắt tuyệt đẹp','Được giải thoát khỏi nỗi đau và sự đau khổ. Do đó, nó tìm kiếm những cách thức để giải quyết nỗi đau và sự đau khổ của cơ thể. Họ không biết cách chịu đựng những niềm vui và những niềm vui tương tự như vậy. Niềm vui trong việc chịu đựng nỗi đau, nhưng nỗi đau lại dễ dàng nảy sinh từ sự ghét bỏ.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(20,20,'vi','Đĩa gỗ nhẹ','Đây là nỗi đau được nói đến, nỗi đau ấy. Sự trốn chạy khỏi sự thật đã tan biến. Chúng ta không thể lánh xa người kiến trúc sư của sự thật, dù chỉ là điều nhỏ nhất. Hãy để những lời buộc tội ấy được đưa ra.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(21,21,'vi','Giày gỗ khí động học','Những sai lầm mà những kẻ mù quáng ca ngợi người sáng tạo. Sự mềm yếu của nó theo thời gian, bởi lòng tham và sự căm ghét. Mọi sai lầm trong việc lựa chọn đều là một sai lầm lớn của nó.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(22,22,'vi','Túi nhôm phong cách mộc mạc','Vì tất cả những điều khác. Ở đây, những lựa chọn này cần được xem xét và không bao giờ có thời điểm nào tương tự. Khi bạn xem xét kỹ, chúng sẽ trở nên rõ ràng.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(23,23,'vi','Đồng hồ nhựa kiểu dáng thanh lịch','Những điều này mang lại nỗi đau một cách công bằng. Cuộc sống ghét sự khoái lạc, nhưng sự lựa chọn lại không mang lại điều gì. Sự tham lam nhỏ nhoi sẽ dẫn đến điều gì sẽ xảy ra. Những niềm vui sẽ trốn tránh và cuối cùng sẽ bị bỏ lại.',1,'2026-06-12 17:01:55','2026-06-12 17:01:55','2026-06-12 17:01:55'),(24,24,'vi','Ví giấy tuyệt vời','Những người được tuyển chọn vào lực lượng dân quân. Họ phải đối mặt với sự phân biệt đối xử khi từ chối hoặc chấp nhận những niềm vui đó. Và những nỗi đau đó sẽ biến mất, mang lại sự hài lòng cho những nỗ lực của họ.',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(25,25,'vi','Túi vải lanh tuyệt đẹp','Lỗi lầm, lỗi lầm, nhưng chẳng ai theo đuổi những điều đáng khen ngợi. Những lời nói ấy dẫn đến hậu quả và cản trở niềm vui. Sự tự do khiến những điều khắc nghiệt trốn tránh, nhưng sự công bằng sẽ giải thích cho những lời buộc tội khắc nghiệt hơn của nó. Một nỗi đau lớn lao và tương tự như vậy, hay nói cách khác, đó là những niềm vui. Có những công việc đáng khen ngợi mà chúng ta có thể làm, ai cũng có thể làm với lòng tham.',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(26,26,'vi','Con dao da tầm thường','Mọi sự đều bắt đầu từ những nỗ lực vất vả. Không ai có thể đạt được sự thật mà không cần nỗ lực. Những nỗ lực đó sẽ dẫn đến những lời chỉ trích. Những niềm vui ấy đã bị che khuất.',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(27,27,'vi','Đồng hồ bê tông tiện dụng','Sẽ có những người từ bỏ những điều này. Từ đây, niềm vui thường mang lại sự dịu dàng lớn lao. Điều đó sẽ đến với một số người. Sẽ có những người từ bỏ mọi điều khó khăn.',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(28,28,'vi','Ghế vải lanh chịu lực cao','Nhưng phải xua đuổi hắn, phải xua đuổi hắn. Mọi sự phiền toái đều do chính hắn gây ra cho chúng ta. Chỉ có sự thật mới là nguồn gốc của hắn.',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(29,29,'vi','Giày len cỡ nhỏ','Những thời điểm như vậy không thể so sánh với bất cứ điều gì. Bởi vì cách thức của sự việc này chính là nguồn gốc của sự tha thứ. Chúng ta buộc tội những kiến trúc sư vĩ đại vì họ đã để những điều đó xảy ra. Bởi vì nỗi đau hiện tại của họ chính là...',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(30,30,'vi','Chiếc xe bê tông tầm thường','Tại Inventore, chúng tôi luôn nỗ lực hết mình để mang đến những điều tốt nhất. Chúng tôi luôn tìm kiếm những điều mới mẻ và không ngừng cải tiến để mang lại những trải nghiệm tuyệt vời nhất cho khách hàng. Chúng tôi luôn cam kết mang đến những sản phẩm và dịch vụ chất lượng cao nhất.',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(31,31,'vi','Ghế len thông minh','Những điều cần loại bỏ dẫn đến những điều cần loại bỏ. Những niềm vui trong cuộc sống mà chúng ta mang lại không phải là những lời ngọt ngào. Điều đó sẽ dễ dàng xảy ra.',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(32,32,'vi','Găng tay lụa tuyệt đẹp','Những lời dạy cao quý cần được tiếp nhận như những nghĩa vụ tất yếu của cuộc đời. Tuy nhiên, không phải mọi thứ đều nên bị từ chối. Ai tuân thủ nguyên tắc này sẽ không tìm kiếm điều gì, cũng không giải thích về sự mềm dẻo trong việc thực hành. Tương tự như vậy, và quả thực là thế. Trong kiến trúc, những khó khăn nhỏ nhặt này xuất hiện trong các nghĩa vụ.',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(33,33,'vi','Dao cắt giấy chuyên dụng','Hoặc là những điều nhỏ nhặt gây phiền toái, hoặc là những điều vô nghĩa trốn tránh sự khoái lạc. Hoặc là những điều che khuất, những cách thức thô ráp, những điều dễ dàng, những điều mà các chức năng mang lại. Từ sự tồn tại, sự thích thú bị cản trở, những điều khác, việc đạt được, bởi vì.',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(34,34,'vi','Chai đá cẩm thạch tuyệt đẹp','Ai có thể đạt được điều mình khao khát nếu không có ai khác? Lòng người không thể bị xua đuổi bởi sự ghét bỏ. Niềm vui của tâm hồn hoặc là sự trốn chạy. Niềm vui không thể trốn chạy khỏi chính nó. Trong chính bản thân, có những điều cần phải vượt qua một cách tự do.',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(35,35,'vi','Dao bằng vải bông phong cách mộc mạc','Thật là vĩ đại khi theo chân những người đó. Họ không biết rằng niềm vui nằm ở việc đạt được tất cả. Hay là không có niềm vui nào cả.',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(36,36,'vi','Chiếc xe cao su tiện dụng','Hầu như không ai biết điều đó. Việc luyện tập chạy bộ quả thực rất thú vị. Những khó khăn trong cuộc sống là kết quả của những sai lầm và sự phân biệt đối xử.',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(37,37,'vi','Ghế lụa phong cách mộc mạc','Những điều lớn lao nhất chính là niềm vui khi từ chối những điều vĩ đại. Sự đau khổ có thể nảy sinh, nhưng sự trốn tránh sẽ dẫn đến hậu quả. Bởi vì điều đó vốn dĩ dễ dàng hơn là tìm kiếm. Mọi người đều tự do ca ngợi nỗi đau và sự vất vả của cuộc sống.',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(38,38,'vi','Bàn phím giấy nhỏ','Các khoản nợ phải trả được ghi nhận theo đúng quy định. Các khoản nợ bị hủy bỏ do lý do hợp lý. Việc từ chối các khoản nợ đáng kể gây cản trở. Chúng tôi chịu trách nhiệm về những khoản nợ chưa thanh toán, đồng thời giải quyết các khoản nợ gây ra đau khổ. Các khoản nợ khác được ghi nhận theo đúng quy định và được xử lý một cách thận trọng.',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(39,39,'vi','Dao cắt bê tông thông minh','Và chính điều đó đã khiến nó trở thành như vậy. Những lỗi lầm lớn hơn đã nhanh chóng xuất hiện. Những điều được nói ra đã khiến người ta mù quáng trước nỗi đau. Nỗi đau ấy tồn tại trong những điều mà người khôn ngoan đã trốn tránh. Nó được sinh ra nhưng lại ghét sự trốn tránh, và không phải là điều khác.',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(40,40,'vi','Máy tính cao su thông minh','Một số người ca ngợi những điều đó. Từ những điều đó nảy sinh những niềm vui, và sự trốn tránh những điều đó mang lại sự thoải mái. Những điều này dường như được coi là những điều cần phải từ chối.',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(41,41,'vi','Chiếc đồng hồ giấy nhỏ','Tôi ghét hắn. Tôi sẽ giải thích tại sao tôi ghét hắn. Những khoái lạc của tâm hồn dẫn đến nỗi đau. Cuộc sống buộc ta phải hành động.',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(42,42,'vi','Chiếc đèn đồng tầm thường','Không ai có thể sánh ngang với họ. Điều đó không phải là vô nghĩa. Lý do khiến họ bị che khuất là do có điều gì đó cản trở.',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(43,43,'vi','Tấm len khí động học','Cách thức giải quyết các cáo buộc. Hãy để niềm vui và sự lựa chọn của kiến trúc sư được thể hiện qua các tác phẩm của họ. Sự thô ráp bao trùm toàn bộ sự tiện nghi. Hãy để tâm hồn được an ủi bởi niềm vui được ca ngợi. Không có sai lầm nào, vì họ sẽ không bỏ rơi.',1,'2026-06-12 17:01:56','2026-06-12 17:01:56','2026-06-12 17:01:56'),(44,44,'vi','Giày đồng Synergistic','Họ lên án những người khôn ngoan vì họ ghét họ. Bằng cách từ chối những niềm vui trong lao động, họ dự đoán những điều khó khăn hơn. Họ không biết rằng lao động là thời gian. Họ không biết rằng chúng ta lên án những lợi ích. Nhưng nỗi đau sinh ra là để chịu đựng một cách công bằng.',1,'2026-06-12 17:01:57','2026-06-12 17:01:57','2026-06-12 17:01:57'),(45,45,'vi','Bàn đá hoa cương chịu lực cao','Chúng ta thường bị cám dỗ bởi những thú vui đó. Tuy nhiên, để vượt qua những thời khắc khó khăn, chúng ta thực sự cần đến những điều đó. Để thỏa mãn khát vọng.',1,'2026-06-12 17:01:57','2026-06-12 17:01:57','2026-06-12 17:01:57'),(46,46,'vi','Ghế băng bằng vải lanh tuyệt đẹp','Những điều mang lại niềm vui. Toàn bộ điều đó. Ai có thể ngăn cản việc theo đuổi và mang lại những niềm vui đó?',1,'2026-06-12 17:01:57','2026-06-12 17:01:57','2026-06-12 17:01:57'),(47,47,'vi','Tấm nhôm nhỏ','Sự đau khổ của chúng ta cũng tương tự như vậy. Thời gian trôi qua cũng tương tự như vậy. Những khó khăn sẽ nhanh chóng qua đi, vì vậy chúng ta sẽ thoát khỏi những vất vả đó. Mọi sự lựa chọn đều do kiến trúc sư đó quyết định. Sự dễ dàng thường nảy sinh từ lao động.',1,'2026-06-12 17:01:57','2026-06-12 17:01:57','2026-06-12 17:01:57'),(48,48,'vi','Giày đá hoa cương khí động học','Đừng để sự phân biệt đó cản trở việc đạt được niềm vui. Đừng để cơ thể bị buộc tội vì chính bản thân nó. Cuộc sống vốn dĩ là như vậy. Hơn nữa, sự trốn tránh những nỗi đau đó là điều cần phải từ chối.',1,'2026-06-12 17:01:57','2026-06-12 17:01:57','2026-06-12 17:01:57'),(49,49,'vi','Ví nhôm khí động học','Những rắc rối này đã được giải quyết. Việc lựa chọn chính là sự lựa chọn. Tuy nhiên, điều đó dẫn đến sự khó chịu và gây ra những đau đớn không đáng có.',1,'2026-06-12 17:01:57','2026-06-12 17:01:57','2026-06-12 17:01:57'),(50,50,'vi','Chiếc đồng hồ nhôm khổng lồ','Vì lý do đó. Chúng giống như vậy. Chúng xảy ra khi sinh ra.',1,'2026-06-12 17:01:57','2026-06-12 17:01:57','2026-06-12 17:01:57'),(51,56,'vi','Áo sơ mi nam màu xanh hải quân của Turtle Check','Áo sơ mi nam Turtle Check màu xanh hải quân. Áo sơ mi màu xanh hải quân. Trang phục thường ngày.',1,'2026-06-12 17:01:57','2026-06-12 17:01:57','2026-06-12 17:01:57'),(52,57,'vi','Quần jean nam Peter England màu xanh dương','Quần jean nam Peter England màu xanh dương. Quần jean màu xanh. Trang phục thường ngày.',1,'2026-06-12 17:01:57','2026-06-12 17:01:57','2026-06-12 17:01:57'),(53,58,'vi','Quần thể thao nam Manchester United màu đen trơn','Quần thể thao nam Manchester United màu đen trơn. Quần thể thao màu đen. Trang phục thường ngày.',1,'2026-06-12 17:01:57','2026-06-12 17:01:57','2026-06-12 17:01:57'),(54,59,'vi','Áo thun nam Puma màu xám','Áo thun nam Puma màu xám. Áo thun màu xám. Trang phục thường ngày.',1,'2026-06-12 17:01:57','2026-06-12 17:01:57','2026-06-12 17:01:57'),(55,60,'vi','Áo len trắng cho bé gái Gini và Jony','Áo len trắng cho bé gái Gini và Jony. Áo màu trắng. Trang phục thường ngày.',1,'2026-06-12 17:01:57','2026-06-12 17:01:57','2026-06-12 17:01:57'),(56,61,'vi','Áo hoodie nam ADIDAS Lfc chính hãng màu xám','Áo hoodie nam ADIDAS Lfc chính hãng màu xám. Áo hoodie màu xám. Quầ